  ('f1000000-0000-0000-0000-000000000001', 'a1111111-1111-1111-1111-111111111111', 'd1111111-1111-1111-1111-111111111111', 'Bank CEO – Vertical Attack from Parking', 'Ace breaches CEO wall from Parking. Buck opens floor from 2F. Nomad holds stair flank with airjabs.', '/images/strategies/mock_001.webp', 'approved', 'e1000000-0000-0000-0000-000000000001'),
