  ('f1000000-0000-0000-0000-000000000003', 'a1111111-1111-1111-1111-111111111111', 'd1111111-1111-1111-1111-111111111113', 'Bank Executive – Azami & Lesion Hold', 'Azami places Kiba barriers on windows. Lesion holds stairs with gu mines. Jäger protects from frags.', '/images/strategies/mock_003.webp', 'approved', 'e1000000-0000-0000-0000-000000000003'),
